210→		writeError("Error: Not authenticated. Run `rudel login` first.");
211→		process.exitCode = 1;
212→		return;
213→	}
214→
215→	write(`Resolving session: ${session}`);
216→	let sessionInfo: Awaited<ReturnType<typeof resolveSession>>;
217→	try {
218→		sessionInfo = await resolveSession(session);
219→	} catch (error) {
220→		writeError(
221→			`Error: ${error instanceof Error ? error.message : String(error)}`,
222→		);
223→		process.exitCode = 1;
224→		return;
225→	}
226→	write(`Found session at: ${sessionInfo.transcriptPath}`);
227→
228→	const gitInfo = await getGitInfo(sessionInfo.projectPath);
229→	const displayName =
230→		gitInfo.gitRemote ||
231→		gitInfo.packageName ||
232→		sessionInfo.projectPath.split("/").pop();
233→	if (displayName) write(`Repository: ${displayName}`);
234→	if (gitInfo.branch) write(`Branch: ${gitInfo.branch}`);
235→
236→	const organizationId =
237→		flags.org ?? (await getProjectOrgId(sessionInfo.projectPath));
238→	if (organizationId) write(`Organization: ${organizationId}`);
239→
240→	write("Building upload request...");
241→	const sessionFile: SessionFile = {
242→		sessionId: sessionInfo.sessionId,
243→		transcriptPath: sessionInfo.transcriptPath,
244→		projectPath: sessionInfo.projectPath,
245→	};
246→
247→	const request = await claudeCodeAdapter.buildUploadRequest(sessionFile, {
248→		tag: flags.tag,
249→		gitInfo,
250→		organizationId,
251→	});
252→
253→	write(`Transcript: ${request.content.length} bytes`);
254→	if (request.subagents && request.subagents.length > 0) {
255→		write(`Subagents: ${request.subagents.length} file(s)`);
256→	}
257→
258→	if (!flags.tag && flags.classify) {
259→		write("Classifying session...");
260→		const classified = await classifySession(request.content);
261→		if (classified) {
262→			(request as { tag?: string }).tag = classified;
263→			write(`Classified as: ${classified}`);
264→		}
265→	}
266→
267→	if (flags.dryRun) {
268→		const preview = {
269→			...request,
270→			content: `[${request.content.length} bytes]`,
271→			subagents: request.subagents?.map((s) => ({
272→				...s,
273→				content: `[${s.content.length} bytes]`,
274→			})),
275→		};
276→		write("Dry run - would upload:");
277→		write(JSON.stringify(preview, null, 2));
278→		return;
279→	}
280→
281→	write("Uploading...");
282→	const result = await uploadSession(request, {
283→		endpoint: flags.endpoint,
284→		// biome-ignore lint/style/noNonNullAssertion: validated above with early return
285→		token: credentials!.token,
286→	});
287→
288→	if (result.success) {
289→		write("Upload successful!");
290→	} else {
291→		writeError(`Upload failed: ${result.error}`);
292→		process.exitCode = 1;
