296→async function runRetryUpload(flags: UploadFlags): Promise<void> {
297→	const credentials = loadCredentials();
298→	if (!credentials) {
299→		p.log.error("Not authenticated. Run `rudel login` first.");
300→		process.exitCode = 1;
301→		return;
302→	}
303→
304→	p.intro("rudel upload --retry");
305→
306→	const failures = await loadFailedUploads();
307→	if (failures.length === 0) {
308→		p.outro("No failed uploads to retry.");
309→		return;
310→	}
311→
312→	p.log.info(`Found ${failures.length} failed upload(s):`);
313→	for (const f of failures.slice(0, 10)) {
314→		p.log.warn(`  ${f.sessionId}: ${f.error} (${f.failedAt})`);
315→	}
316→	if (failures.length > 10) {
317→		p.log.warn(`  ...and ${failures.length - 10} more`);
318→	}
319→
320→	const shouldRetry = await p.confirm({
321→		message: `Retry all ${failures.length} failed upload(s)?`,
322→		initialValue: true,
323→	});
324→
325→	if (p.isCancel(shouldRetry) || !shouldRetry) {
326→		p.cancel("Retry cancelled.");
327→		return;
328→	}
329→
330→	const endpoint = flags.endpoint;
331→
332→	type RetryItem = BatchUploadItem & {
333→		failure: (typeof failures)[number];
334→	};
335→
336→	const items: RetryItem[] = failures.map((f) => ({
337→		sessionId: f.sessionId,
338→		label: f.sessionId,
339→		transcriptPath: f.transcriptPath,
340→		projectPath: f.projectPath,
341→		source: f.source,
342→		organizationId: f.organizationId,
343→		failure: f,
344→	}));
345→
346→	const summary = await runBatchUpload({
347→		items,
348→		label: "Retrying uploads...",
349→		concurrency: flags.concurrency,
350→		upload: async (item, onRetry) => {
351→			const adapter = item.failure.source
352→				? getAdapter(item.failure.source)
353→				: claudeCodeAdapter;
354→			const sessionFile: SessionFile = {
355→				sessionId: item.failure.sessionId,
356→				transcriptPath: item.failure.transcriptPath,
357→				projectPath: item.failure.projectPath,
358→			};
359→			const gitInfo = await getGitInfo(item.failure.projectPath);
360→			const organizationId =
361→				flags.org ??
362→				item.failure.organizationId ??
363→				(await getProjectOrgId(item.failure.projectPath));
364→
365→			const request = await adapter.buildUploadRequest(sessionFile, {
366→				tag: flags.tag,
367→				gitInfo,
368→				organizationId,
369→			});
370→
371→			return uploadSession(request, {
372→				endpoint,
373→				token: credentials.token,
374→				onRetry,
375→			});
376→		},
377→	});
378→
379→	renderBatchSummary(summary);
380→
381→	p.outro("Done!");
382→
383→	if (summary.failed > 0) {
384→		process.exitCode = 1;
385→	}
386→}
387→
388→async function runUpload(
389→	flags: UploadFlags,
390→	...sessions: string[]
391→): Promise<void> {
392→	if (flags.retry) {
393→		return runRetryUpload(flags);
394→	}
395→	if (sessions.length === 0) {
396→		return runInteractiveUpload(flags);
397→	}
398→	return runSingleUpload(flags, sessions[0] as string);
399→}
400→
401→export const uploadCommand = buildCommand({
402→	loader: async () => ({ default: runUpload }),
403→	parameters: {
404→		positional: {
405→			kind: "array",
406→			parameter: {
407→				brief: "Session ID or path to a session .jsonl file",
408→				parse: String,
409→				placeholder: "session",
410→			},
411→		},
412→		flags: {
413→			tag: {
414→				kind: "enum",
415→				values: [...SESSION_TAGS],
416→				brief: "Session tag/category",
417→				optional: true,
418→			},
419→			endpoint: {
420→				kind: "parsed",
421→				parse: String,
422→				brief: "Override the upload endpoint URL",
423→				default: DEFAULT_ENDPOINT,
424→			},
425→			classify: {
426→				kind: "boolean",
427→				brief: "Auto-classify session tag using Claude CLI",
428→				default: false,
429→			},
430→			dryRun: {
431→				kind: "boolean",
432→				brief: "Preview what would be uploaded without sending",
433→				default: false,
434→			},
435→			org: {
436→				kind: "parsed",
437→				parse: String,
438→				brief: "Override the organization ID to upload to",
439→				optional: true,
440→			},
441→			retry: {
442→				kind: "boolean",
443→				brief: "Retry previously failed uploads",
444→				default: false,
445→			},
446→			concurrency: {
447→				kind: "parsed",
448→				parse: Number,
449→				brief: "Max concurrent uploads",
450→				default: "5",
451→			},
452→		},
453→		aliases: {
454→			t: "tag",
455→			c: "classify",
456→			n: "dryRun",
457→			o: "org",
458→			r: "retry",
459→			j: "concurrency",
460→		},
461→	},
462→	docs: {
463→		brief:
464→			"Upload session transcripts (Claude Code & Codex). No args = interactive project picker.",
465→	},
466→});
